static void uart_init(uint32_t baud_rate) {
    /* Assuming 16MHz system clock */
    uint32_t sys_clk = 16000000;
    uint32_t brd = sys_clk / (16 * baud_rate);
    uint32_t frac = (((sys_clk * 4) / baud_rate) + 1) / 2;

    UART0_CR = 0;                           /* Disable UART */
    UART0_IBRD = brd;                       /* Integer baud rate */
    UART0_FBRD = frac & 0x3F;              /* Fractional baud rate */
    UART0_LCRH = UART_LCRH_WLEN_8 | UART_LCRH_FEN;  /* 8N1, FIFO enable */
    UART0_CR = UART_CR_UARTEN | UART_CR_TXE | UART_CR_RXE;
}

static void uart_putc(char c) {
    while (UART0_FR & UART_FR_TXFF);       /* Wait for TX FIFO space */
    UART0_DR = (uint32_t)c;
}

static char uart_getc(void) {
    while (UART0_FR & UART_FR_RXFE);       /* Wait for RX data */
    return (char)(UART0_DR & 0xFF);
}

static bool uart_rx_ready(void) {
    return !(UART0_FR & UART_FR_RXFE);
}

static void uart_puts(const char *s) {
    while (*s) {
        if (*s == '\n') uart_putc('\r');
        uart_putc(*s++);
    }
}

static void uart_put_hex8(uint8_t val) {
    const char hex[] = "0123456789ABCDEF";
    uart_putc(hex[(val >> 4) & 0x0F]);
    uart_putc(hex[val & 0x0F]);
}

static void uart_put_hex32(uint32_t val) {
    for (int i = 28; i >= 0; i -= 4) {
        const char hex[] = "0123456789ABCDEF";
        uart_putc(hex[(val >> i) & 0x0F]);
    }
}

static void uart_put_dec(uint32_t val) {
    char buf[12];
    int i = 0;
    if (val == 0) {
        uart_putc('0');
        return;
    }
    while (val > 0 && i < (int)sizeof(buf) - 1) {
        buf[i++] = '0' + (val % 10);
        val /= 10;
    }
    while (--i >= 0) {
        uart_putc(buf[i]);
    }
}

