static void cmd_get_config(int argc, char *argv[]) {
    (void)argc; (void)argv;
    uart_puts("\n--- Device Configuration ---\n");

    for (int i = 0; i < CONFIG_FIELD_COUNT; i++) {
        uart_puts("  ");
        uart_puts(config_field_names[i]);
        uart_puts(": ");

        if (config_field_sensitive[i]) {
            uart_puts("[REDACTED]\n");
            continue;
        }

        switch ((config_field_id_t)i) {
            case CONFIG_FIELD_DEVICE_ID:
                uart_puts(g_device_config.device_id);
                break;
            case CONFIG_FIELD_FW_VERSION:
                uart_puts(g_device_config.fw_version);
                break;
            case CONFIG_FIELD_SENSOR_TYPE:
                uart_puts(g_device_config.sensor_type);
                break;
            case CONFIG_FIELD_SAMPLE_RATE:
                uart_put_dec(g_device_config.sample_rate_hz);
                break;
            case CONFIG_FIELD_NETWORK_MODE:
                uart_puts(g_device_config.network_mode);
                break;
            case CONFIG_FIELD_UPTIME:
                uart_put_dec(g_device_config.uptime_sec);
                break;
            case CONFIG_FIELD_ERROR_COUNT:
                uart_put_dec(g_device_config.error_count);
                break;
            case CONFIG_FIELD_LAST_CALIBRATION:
                uart_put_dec(g_device_config.last_calibration_epoch);
                break;
            default:
                uart_puts("[REDACTED]");
                break;
        }
        uart_puts("\n");
    }
}

static void cmd_dump_memory(int argc, char *argv[]) {
    if (argc < 3) {
        uart_puts("Usage: dump_memory <hex_addr> <hex_size>\n");
        uart_puts("  Max size: 0x1000 (4096 bytes)\n");
        return;
    }

    uint32_t addr, size;
    if (!parse_hex(argv[1], &addr) || !parse_hex(argv[2], &size)) {
        uart_puts("ERROR: Invalid hex argument.\n");
        return;
    }

    /* Enforce alignment */
    addr &= ~0x3;

    if (!is_region_allowed(addr, size, allowed_read_regions)) {
        uart_puts("ERROR: Address range not in allowed regions.\n");
        uart_puts("Use 'regions' command to see allowed areas.\n");
        audit_log("DENIED: memory dump out of bounds");
        return;
    }

    uart_puts("\nMemory dump at 0x");
    uart_put_hex32(addr);
    uart_puts(", size 0x");
    uart_put_hex32(size);
    uart_puts(":\n");

    const uint8_t *ptr = (const uint8_t *)addr;
    for (uint32_t i = 0; i < size; i++) {
        if ((i % 16) == 0) {
            if (i > 0) uart_puts("\n");
            uart_puts("  0x");
            uart_put_hex32(addr + i);
            uart_puts(": ");
        }
        uart_put_hex8(ptr[i]);
        uart_putc(' ');
    }
    uart_puts("\n");

    audit_log("Memory dump executed");
}

static void cmd_read_flash(int argc, char *argv[]) {
    if (argc < 2) {
        uart_puts("Usage: read_flash <sector_num> [word_count]\n");
        return;
    }

    uint32_t sector;
    if (!parse_hex(argv[1], &sector)) {
        uart_puts("ERROR: Invalid sector number.\n");
        return;
    }

    uint32_t word_count = 64;  /* Default: 256 bytes */
    if (argc >= 3) {
        if (!parse_hex(argv[2], &word_count)) {
            uart_puts("ERROR: Invalid word count.\n");
            return;
        }
    }

    /* Limit read size */
    if (word_count > (FLASH_SECTOR_SIZE / 4)) {
        word_count = FLASH_SECTOR_SIZE / 4;
    }

    uint32_t flash_addr = FLASH_BASE + (sector * FLASH_SECTOR_SIZE);
    uint32_t read_size = word_count * 4;

    if (!is_region_allowed(flash_addr, read_size, allowed_flash_regions)) {
        uart_puts("ERROR: Flash sector ");
        uart_put_dec(sector);
        uart_puts(" is not in allowed read regions.\n");
        uart_puts("Protected sectors: bootloader, keys, secure config.\n");
        audit_log("DENIED: flash read restricted sector");
        return;
    }

    uart_puts("\nFlash sector ");
    uart_put_dec(sector);
    uart_puts(" at 0x");
    uart_put_hex32(flash_addr);
    uart_puts(":\n");

    const uint32_t *ptr = (const uint32_t *)flash_addr;
    for (uint32_t i = 0; i < word_count; i++) {
        if ((i % 4) == 0) {
            if (i > 0) uart_puts("\n");
            uart_puts("  0x");
            uart_put_hex32(flash_addr + (i * 4));
            uart_puts(": ");
        }
        uart_put_hex32(ptr[i]);
        uart_putc(' ');
    }
    uart_puts("\n");

    audit_log("Flash read executed");
}

static void cmd_regions(int argc, char *argv[]) {
    (void)argc; (void)argv;

    uart_puts("\n--- Allowed Memory Regions ---\n");
    for (int i = 0; allowed_read_regions[i].name != NULL; i++) {
        uart_puts("  ");
        uart_puts(allowed_read_regions[i].name);
        uart_puts(": 0x");
        uart_put_hex32(allowed_read_regions[i].start);
        uart_puts(" - 0x");
        uart_put_hex32(allowed_read_regions[i].end);
        uart_puts("\n");
    }

    uart_puts("\n--- Allowed Flash Regions ---\n");
    for (int i = 0; allowed_flash_regions[i].name != NULL; i++) {
        uart_puts("  ");
        uart_puts(allowed_flash_regions[i].name);
        uart_puts(": 0x");
        uart_put_hex32(allowed_flash_regions[i].start);
        uart_puts(" - 0x");
        uart_put_hex32(allowed_flash_regions[i].end);
        uart_puts("\n");
    }
}

