static void cmd_audit_log_show(int argc, char *argv[]) {
    (void)argc; (void)argv;
    uart_puts("\n--- Audit Log ---\n");

    uint32_t start = 0;
    uint32_t count = g_audit_index;
    if (count > AUDIT_LOG_SIZE) {
        start = g_audit_index - AUDIT_LOG_SIZE;
        count = AUDIT_LOG_SIZE;
    }

    for (uint32_t i = start; i < start + count; i++) {
        audit_entry_t *entry = &g_audit_log[i % AUDIT_LOG_SIZE];
        uart_puts("  [");
        uart_put_dec(entry->timestamp);
        uart_puts(" ms] ");
        uart_puts(entry->event);
        uart_puts("\n");
    }

    if (count == 0) {
        uart_puts("  (empty)\n");
    }
}

/* ============================================================
 * Command Table and Dispatcher
 * ============================================================ */

typedef void (*cmd_handler_t)(int argc, char *argv[]);

typedef struct {
    const char *name;
    cmd_handler_t handler;
    bool requires_auth;
} cmd_entry_t;

static const cmd_entry_t command_table[] = {
    { "help",           cmd_help,             false },
    { "auth",           cmd_auth_challenge,   false },
    { "auth_response",  cmd_auth_response,    false },
    { "logout",         cmd_logout,           false },
    { "status",         cmd_status,           false },  /* Basic status is public */
    { "get_config",     cmd_get_config,       true  },
    { "dump_memory",    cmd_dump_memory,      true  },
    { "read_flash",     cmd_read_flash,       true  },
    { "sensor_data",    cmd_sensor_data,      true  },
    { "error_log",      cmd_error_log,        true  },
    { "audit_log",      cmd_audit_log_show,   true  },
    { "regions",        cmd_regions,          true  },
    { NULL,             NULL,                 false }
};

/* ============================================================
 * Session Management
 * ============================================================ */
static bool check_session_valid(void) {
    if (!g_session.authenticated) return false;

    /* Check session timeout */
    uint32_t elapsed_ms = g_systick_ms - g_session.session_start_tick;
    if (elapsed_ms > (SESSION_TIMEOUT_SEC * 1000)) {
        g_session.authenticated = false;
        g_session.session_start_tick = 0;
        uart_puts("\nWARNING: Session timed out. Re-authenticate.\n");
        audit_log("Session timeout");
        return false;
    }

    return true;
}

static bool check_rate_limit(void) {
    uint32_t elapsed = g_systick_ms - g_session.last_cmd_tick;
    if (elapsed < CMD_RATE_LIMIT_MS) {
        return false;
    }
    g_session.last_cmd_tick = g_systick_ms;
    return true;
}

/* ============================================================
 * Command Parser
 * ============================================================ */
static void parse_and_execute(char *line) {
    /* Tokenize */
    char *argv[MAX_ARGS];
    int argc = 0;

    char *p = line;
    while (*p && argc < MAX_ARGS) {
        /* Skip whitespace */
        while (*p == ' ' || *p == '\t') p++;
        if (*p == '\0') break;

        argv[argc++] = p;

        /* Find end of token */
        while (*p && *p != ' ' && *p != '\t') p++;
        if (*p) *p++ = '\0';
    }

    if (argc == 0) return;

    /* Rate limiting */
    if (!check_rate_limit()) {
        uart_puts("ERROR: Rate limit. Wait before next command.\n");
        return;
    }

    /* Find command */
    for (int i = 0; command_table[i].name != NULL; i++) {
        if (strcmp(argv[0], command_table[i].name) == 0) {
            /* Check authentication requirement */
            if (command_table[i].requires_auth && !check_session_valid()) {
                uart_puts("ERROR: Authentication required. Use 'auth' to begin.\n");
                audit_log("DENIED: unauthenticated command");
                return;
            }

            /* Execute command */
            command_table[i].handler(argc, argv);
            return;
        }
    }

    uart_puts("ERROR: Unknown command '");
    uart_puts(argv[0]);
    uart_puts("'. Type 'help' for available commands.\n");
}

/* ============================================================
 * Command Line Reader
 * ============================================================ */
static void read_command_line(char *buf, size_t buf_size) {
    size_t pos = 0;
    memset(buf, 0, buf_size);

    while (pos < buf_size - 1) {
        char c = uart_getc();

        if (c == '\r' || c == '\n') {
            uart_puts("\r\n");
            buf[pos] = '\0';
            return;
        } else if (c == '\b' || c == 0x7F) {
            /* Backspace */
            if (pos > 0) {
                pos--;
                uart_puts("\b \b");
            }
        } else if (c >= 0x20 && c < 0x7F) {
            buf[pos++] = c;
            uart_putc(c);
        }
        /* Ignore other control characters */
    }
    buf[pos] = '\0';
}

/* ============================================================
 * SysTick Handler (called every 1ms)
 * ============================================================ */
void SysTick_Handler(void) {
    g_systick_ms++;

    /* Update uptime every second */
    if ((g_systick_ms % 1000) == 0) {
        g_device_config.uptime_sec++;
    }
}

static void systick_init(void) {
    /* Configure SysTick for 1ms interrupt at 16MHz */
    SYSTICK_RVR = 16000 - 1;
    SYSTICK_CVR = 0;
    SYSTICK_CSR = 0x07;  /* Enable, interrupt, use processor clock */
}

/* ============================================================
 * Diagnostic Console Main Entry
 * ============================================================ */
void diag_console_init(void) {
    /* Initialize hardware */
    systick_init();
    uart_init(115200);

    /* CRITICAL: Disable JTAG/SWD in production */
    disable_debug_interfaces();

    /* Initialize session state */
    memset((void *)&g_session, 0, sizeof(g_session));

    audit_log("Diagnostic console initialized");

    /* Print banner */
    uart_puts("\r\n");
    uart_puts("========================================\n");
    uart_puts("  Industrial IoT Sensor - Diag Console\n");
    uart_puts("  FW: ");
    uart_puts(g_device_config.fw_version);
    uart_puts("  ID: ");
    uart_puts(g_device_config.device_id);
    uart_puts("\n");
    uart_puts("========================================\n");
#if PRODUCTION_BUILD
    uart_puts("  [PRODUCTION BUILD - JTAG DISABLED]\n");
#else
    uart_puts("  [DEVELOPMENT BUILD - JTAG ENABLED]\n");
#endif
    uart_puts("  Authentication required for diagnostics.\n");
    uart_puts("  Type 'help' for commands.\n");
    uart_puts("========================================\n\n");
}

void diag_console_run(void) {
    char cmd_buf[MAX_CMD_LEN];

    while (1) {
        /* Show prompt with auth status */
        if (g_session.authenticated) {
            uart_puts("[auth] > ");
        } else {
            uart_puts("[noauth] > ");
        }

        read_command_line(cmd_buf, sizeof(cmd_buf));

        if (cmd_buf[0] != '\0') {
            parse_and_execute(cmd_buf);
        }
    }
}

/* ============================================================
 * Main Entry Point
 * ============================================================ */
int main(void) {
    diag_console_init();
    diag_console_run();
    return 0;
}